+
+    var i = offset;
+    const end = data.len - 16;
+
+    while (i <= end) : (i += 16) {
+        const chunk: @Vector(16, u8) = data[i..][0..16].*;
+
+        const is_space = chunk == @as(@Vector(16, u8), @splat(' '));
+        const is_tab = chunk == @as(@Vector(16, u8), @splat('\t'));
