+            var it = data.map.iterator();
+            var first = true;
+            while (it.next()) |entry| {
+                if (!first) try writer.writeByte(',');
+                first = false;
+
+                // Key
+                try writer.writeByte('"');
+                try writeEscapedString(entry.key_ptr.*, writer);
+                try writer.writeByte('"');
+                try writer.writeByte(':');
+
+                // Value
+                try stringifyPyObject(entry.value_ptr.*, writer);
+            }
+
+            try writer.writeByte('}');
+        },
+    }
