+                '\\' => try writer.writeAll("\\\\"),
+                '\x08' => try writer.writeAll("\\b"),
+                '\x0C' => try writer.writeAll("\\f"),
+                '\n' => try writer.writeAll("\\n"),
+                '\r' => try writer.writeAll("\\r"),
+                '\t' => try writer.writeAll("\\t"),
+                else => try writer.print("\\u{x:0>4}", .{c}),
+            }
